import React from 'react';

const UserCard = ({ user, onClick }) => {
  const getStatusColor = (status) => {
    switch (status) {
      case 'online': return 'bg-green-500';
      case 'away': return 'bg-yellow-500';
      case 'offline': return 'bg-gray-500';
      default: return 'bg-green-500';
    }
  };

  const getAvailabilityColor = (availability) => {
    switch (availability) {
      case 'Available': return 'bg-green-500 text-white';
      case 'Busy': return 'bg-red-500 text-white';
      case 'In Meeting': return 'bg-blue-500 text-white';
      case 'Do Not Disturb': return 'bg-purple-500 text-white';
      case 'Lunch Break': return 'bg-orange-500 text-white';
      case 'Offline': return 'bg-gray-500 text-white';
      default: return 'bg-green-500 text-white';
    }
  };

  return (
    <div 
      className="bg-gray-800 rounded-lg p-4 flex items-center gap-3 cursor-pointer hover:bg-gray-700 transition-colors"
      onClick={onClick}
    >
      <div className="relative">
        <img 
          src={user.avatar} 
          alt={`${user.name} Profile`} 
          className="w-10 h-10 rounded-full object-cover"
        />
        <div className={`absolute -bottom-1 -right-1 w-4 h-4 ${getStatusColor(user.status)} rounded-full border-2 border-gray-800`}></div>
      </div>
      <div className="flex-1">
        <h3 className="text-white font-medium">{user.name}</h3>
        <p className="text-gray-400 text-sm">{user.title}</p>
      </div>
      <div className={`text-xs px-2 py-1 rounded ${getAvailabilityColor(user.availability)}`}>
        {user.availability}
      </div>
    </div>
  );
};

export default UserCard;
